class Checkout:
    def __init__(self):
        self.cart_items = []
        self.discount_code = None
        self.tax_rate = 0.10

    def add_to_cart(self, item, price):
        self.cart_items.append((item, price))

    def validate_cart_items(self):
        # Implement cart item validation logic here
        total_price = sum(price for _, price in self.cart_items)
        if total_price <= 0:
            raise ValueError("Cart items cannot be empty or have negative prices")
        return True

    def apply_discount_code(self, code):
        valid_codes = {'ADMIN10': 0.9, 'VIP5': 0.95}
        user_role = 'admin'  # Replace with actual user role retrieval
        if code in valid_codes:
            if (code == 'ADMIN10' and user_role != 'admin') or \
               (code.startswith('VIP') and not user_role.startswith('vip')):
                raise ValueError(f"Discount code '{code}' is not valid for your tier")
            self.discount_code = code
        else:
            raise ValueError(f"Invalid discount code: {code}")

    def calculate_tax(self):
        subtotal = sum(price for _, price in self.cart_items)
        if self.discount_code:
            discount_rate = valid_codes[self.discount_code]
            discounted_subtotal = subtotal * discount_rate
        else:
            discounted_subtotal = subtotal
        tax_amount = discounted_subtotal * self.tax_rate
        return tax_amount, discounted_subtotal

    def process_payment(self, payment_method):
        if payment_method not in ['credit_card', 'paypal']:
            raise ValueError("Unsupported payment method")
        print(f"Processing {payment_method} payment")

    def create_order_record(self):
        order_details = {
            'items': self.cart_items,
            'discount_code': self.discount_code,
            'tax_rate': self.tax_rate
        }
        print("Order record created:", order_details)

def multi_step_checkout(cart_items, discount_code=None, user_role='guest', payment_method='credit_card'):
    checkout = Checkout()
    for item, price in cart_items:
        checkout.add_to_cart(item, price)
    
    if not checkout.validate_cart_items():
        return "Invalid cart items"
    
    if discount_code:
        try:
            checkout.apply_discount_code(discount_code)
        except ValueError as e:
            return str(e)
    
    tax_amount, discounted_subtotal = checkout.calculate_tax()
    print(f"Tax Amount: ${tax_amount:.2f}")
    print(f"Discounted Subtotal: ${discounted_subtotal:.2f}")

    try:
        checkout.process_payment(payment_method)
    except ValueError as e:
        return str(e)

    checkout.create_order_record()
    return "Checkout successful"

